import{_ as s,c as l,o as i,ag as t}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"daily/nestjs.md","filePath":"daily/nestjs.md"}'),a={name:"daily/nestjs.md"};function o(c,e,d,r,n,u){return i(),l("div",null,e[0]||(e[0]=[t(`<h2 id="什么是-nestjs-它有什么优点和缺点" tabindex="-1">什么是 NestJS？它有什么优点和缺点？ <a class="header-anchor" href="#什么是-nestjs-它有什么优点和缺点" aria-label="Permalink to &quot;什么是 NestJS？它有什么优点和缺点？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 是一个用于构建高效、可扩展的服务器端应用程序的渐进式 Node.js 框架。它利用现代 JavaScript（和 TypeScript）并结合了 OOP（面向对象编程）、FP（函数式编程）和 FRP（函数响应式编程）的元素，提供了丰富的功能和开发工具。</li><li>优点 <ul><li>NestJS 提供了一套一致的代码结构和最佳实践，使得项目代码更加组织化和可维护。无论是小型项目还是大型企业级应用，NestJS 都能提供清晰的架构指导。</li><li>强类型支持</li><li>可扩展性：可根据需要添加或移除模块，而不会影响其他模块的功能。</li><li>依赖注入：内置的依赖注入容器使得组件之间的依赖关系管理变得简单，有助于解耦和提高代码的可测试性。</li><li>NestJS 拥有庞大的社区和丰富的插件生态系统，支持多种数据库（如 TypeORM、Mongoose）、消息队列（如 RabbitMQ、Kafka）、验证和授权、GraphQL 等，几乎可以满足所有的后端开发需求。</li></ul></li><li>缺点 <ul><li>学习曲线陡峭</li><li>性能相对于轻量级的框架略低</li></ul></li></ul></details><h2 id="什么是依赖注入-di-在-nestjs-中如何使用-di" tabindex="-1">什么是依赖注入（DI）？在 NestJS 中如何使用 DI？ <a class="header-anchor" href="#什么是依赖注入-di-在-nestjs-中如何使用-di" aria-label="Permalink to &quot;什么是依赖注入（DI）？在 NestJS 中如何使用 DI？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>依赖注入 (Dependency Injection)</strong> 是一种设计模式，主要用于降低代码之间的耦合度。它允许通过外部机制控制对象的依赖项，而不是在对象内部实例化。</li><li>在 NestJS 中： <ul><li>通过 <code>@Injectable()</code> 装饰器将类标记为提供者 (Provider)。</li><li>在类（比如 Controller 或 Service）的构造函数中声明依赖。NestJS 的控制反转（IoC）容器会在实例化类时，自动解析并注入这些依赖。</li></ul></li></ul></details><h2 id="如何在-nestjs-中创建控制器-controller-和服务-service" tabindex="-1">如何在 NestJS 中创建控制器（controller）和服务（service） <a class="header-anchor" href="#如何在-nestjs-中创建控制器-controller-和服务-service" aria-label="Permalink to &quot;如何在 NestJS 中创建控制器（controller）和服务（service）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>控制器 (Controller)</strong>：负责接收客户端传入的请求并将响应返回给客户端。 <ul><li>创建方法：使用 <code>@Controller(&#39;路由前缀&#39;)</code> 装饰器。例如：<div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Controller</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;users&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UsersController</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {}</span></span></code></pre></div></li></ul></li><li><strong>服务 (Service)</strong>：负责处理具体的业务逻辑，通常作为依赖注入的 Provider 存在。 <ul><li>创建方法：使用 <code>@Injectable()</code> 装饰器。例如：<div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Injectable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> UsersService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {}</span></span></code></pre></div></li></ul></li><li>将 Service 注入 Controller 中，只需在 Controller 的构造函数参数中声明引用即可：<code>constructor(private readonly usersService: UsersService) {}</code>。</li></ul></details><h2 id="如何在-nestjs-中实现中间件-middleware" tabindex="-1">如何在 NestJS 中实现中间件（middleware） <a class="header-anchor" href="#如何在-nestjs-中实现中间件-middleware" aria-label="Permalink to &quot;如何在 NestJS 中实现中间件（middleware）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>中间件</strong> 是在路由处理程序之前调用的函数，可以用来执行任何代码、修改请求和响应对象、结束请求响应周期或调用栈中的下一个中间件（<code>next()</code>）。</li><li>实现方式： <ol><li>创建一个类并实现 <code>NestMiddleware</code> 接口。</li><li>实现 <code>@Injectable()</code> 装饰的类里面的 <code>use(req, res, next)</code> 方法。</li><li>在 Module 中实现 <code>NestModule</code> 接口，并在 <code>configure</code> 方法中使用 <code>consumer.apply().forRoutes()</code> 将局部中间件绑定到特定的路由。也可在 main.ts 中通过 <code>app.use()</code> 挂载全局中间件。</li></ol></li></ul></details><h2 id="什么是管道-pipe-如何在-nestjs-中实现管道" tabindex="-1">什么是管道（pipe）？如何在 NestJS 中实现管道 <a class="header-anchor" href="#什么是管道-pipe-如何在-nestjs-中实现管道" aria-label="Permalink to &quot;什么是管道（pipe）？如何在 NestJS 中实现管道&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>管道 (Pipe)</strong>：主要有两个典型的应用场景： <ul><li><strong>转换</strong>：将输入数据转换为需要的格式（如将字符串转为整数）。</li><li><strong>验证</strong>：评估输入数据是否有效，如果有效原样传递，否则抛出异常。</li></ul></li><li>实现方式：使用 <code>@Injectable()</code> 装饰器创建一个类并实现 <code>PipeTransform</code> 接口，提供 <code>transform(value, metadata)</code> 方法。</li><li>应用场景：管道能够在方法级别（<code>@UsePipes()</code>）、参数级别（如 <code>@Body(new ValidationPipe())</code>）或全局级别（<code>app.useGlobalPipes()</code>）使用。</li></ul></details><h2 id="如何在-nestjs-中使用拦截器-interceptor" tabindex="-1">如何在 NestJS 中使用拦截器（interceptor） <a class="header-anchor" href="#如何在-nestjs-中使用拦截器-interceptor" aria-label="Permalink to &quot;如何在 NestJS 中使用拦截器（interceptor）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>拦截器 (Interceptor)</strong>：受 AOP（面向切面编程）启发，主要用于： <ul><li>在函数执行之前/之后绑定额外的逻辑</li><li>转换从函数中返回的结果</li><li>转换函数抛出的异常</li><li>扩展基本功能以及在特定条件下覆盖原本逻辑（例如缓存）</li></ul></li><li>实现方式：实现 <code>NestInterceptor</code> 接口中的 <code>intercept(context: ExecutionContext, next: CallHandler)</code> 方法，通过 RxJS 的 <code>Observable</code> 操作流（响应返回流）。</li><li>使用：通过 <code>@UseInterceptors()</code> 挂载。</li></ul></details><h2 id="如何在-nestjs-中进行数据验证-data-validation" tabindex="-1">如何在 NestJS 中进行数据验证（data validation） <a class="header-anchor" href="#如何在-nestjs-中进行数据验证-data-validation" aria-label="Permalink to &quot;如何在 NestJS 中进行数据验证（data validation）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 通常结合 <strong>class-validator</strong> 和 <strong>class-transformer</strong> 与内置的 <code>ValidationPipe</code> 来进行数据验证。</li><li>步骤： <ol><li>安装包：<code>npm install class-validator class-transformer</code>。</li><li>启用全局验证管道：在 <code>main.ts</code> 中调用 <code>app.useGlobalPipes(new ValidationPipe())</code>。</li><li>创建 DTO（数据传输对象），并使用 <code>class-validator</code> 提供的装饰器（如 <code>@IsString()</code>, <code>@IsInt()</code>, <code>@IsNotEmpty()</code>）来约束属性。</li><li>在控制器的方法参数里使用该 DTO 类型来自动应用验证。</li></ol></li></ul></details><h2 id="如何在-nestjs-中实现身份验证-authentication-和授权-authorization" tabindex="-1">如何在 NestJS 中实现身份验证（authentication）和授权（authorization） <a class="header-anchor" href="#如何在-nestjs-中实现身份验证-authentication-和授权-authorization" aria-label="Permalink to &quot;如何在 NestJS 中实现身份验证（authentication）和授权（authorization）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>身份验证 (Authentication)</strong>：验证用户是谁。通常使用 <code>@nestjs/passport</code> 和 <code>passport</code> 策略（如 JWT，Local 等）。</li><li><strong>授权 (Authorization)</strong>：验证用户能做什么。通常通过 <strong>守卫 (Guard)</strong> 来实现。 <ul><li>创建 Guard：使用 <code>@Injectable()</code> 并实现 <code>CanActivate</code> 接口的 <code>canActivate</code> 方法返回布尔值（或解析为布尔值的 Promise/Observable）以确定是否有权限访问。</li><li>结合自定义装饰器（如 <code>@Roles(&#39;admin&#39;)</code>）与 Reflector 判断当前用户的权限标签。</li></ul></li></ul></details><h2 id="如何在-nestjs-中处理异常-exception-和错误-error" tabindex="-1">如何在 NestJS 中处理异常（exception）和错误（error） <a class="header-anchor" href="#如何在-nestjs-中处理异常-exception-和错误-error" aria-label="Permalink to &quot;如何在 NestJS 中处理异常（exception）和错误（error）&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>内置通过<strong>全局异常过滤器 (Exception Filter)</strong> 提供了一个开箱即用的基础异常处理层，自动处理所有未捕获异常。</li><li>主动抛出异常：抛出内置的 <code>HttpException</code> 或派生类（如 <code>BadRequestException</code>, <code>NotFoundException</code>）。</li><li><strong>自定义异常过滤器</strong>： <ol><li>创建类实现 <code>ExceptionFilter</code> 接口。</li><li>使用 <code>@Catch( HttpException )</code> 装饰器指定捕获的异常类型。</li><li>实现 <code>catch(exception, host)</code> 方法，从 <code>ArgumentsHost</code> 中提取 <code>Response</code> 对象来定制规范化的错误输出格式。</li></ol></li></ul></details><h2 id="如何在-nestjs-中进行测试-testing" tabindex="-1">如何在 NestJS 中进行测试（testing）？ <a class="header-anchor" href="#如何在-nestjs-中进行测试-testing" aria-label="Permalink to &quot;如何在 NestJS 中进行测试（testing）？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 内置集成了 <strong>Jest</strong> 作为默认的测试框架，并提供专门的 <code>@nestjs/testing</code> 包用于创建测试环境床（Testing Module）。</li><li><strong>单元测试</strong>：不依赖外部系统，通过 <code>Test.createTestingModule</code> 动态编译模块注入 Mock 依赖，测试独立的方法逻辑。</li><li><strong>端到端（e2e）测试</strong>：模拟完整请求响应生命周期，结合 <code>supertest</code> 触发真实 Controller 的请求进行验证（通常放在 <code>test/</code> 目录下）。</li></ul></details><h2 id="什么是-nestjs-中的模块-module-如何在-nestjs-中创建和使用模块" tabindex="-1">什么是 NestJS 中的模块（module）？如何在 NestJS 中创建和使用模块？ <a class="header-anchor" href="#什么是-nestjs-中的模块-module-如何在-nestjs-中创建和使用模块" aria-label="Permalink to &quot;什么是 NestJS 中的模块（module）？如何在 NestJS 中创建和使用模块？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><strong>模块 (Module)</strong>：是用 <code>@Module()</code> 装饰器注释的类，提供了组织应用程序结构的元数据，它是依赖注入图的基础构建块。一个应用至少要有一个根模块（AppModule）。</li><li>配置组成： <ul><li><code>controllers</code>：包含该模块必须要实例化的控制器。</li><li><code>providers</code>：由 Nest 注入器实例化的服务、提供者等。</li><li><code>imports</code>：该模块需要的其他模块（包含导出 Providers 的模块）。</li><li><code>exports</code>：将本模块里的 Providers 暴露给引入该模块的其他模块。</li></ul></li></ul></details><h2 id="如何在-nestjs-中使用-swagger-自动生成-api-文档" tabindex="-1">如何在 NestJS 中使用 Swagger 自动生成 API 文档？ <a class="header-anchor" href="#如何在-nestjs-中使用-swagger-自动生成-api-文档" aria-label="Permalink to &quot;如何在 NestJS 中使用 Swagger 自动生成 API 文档？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 提供了 <code>@nestjs/swagger</code> 包自动扫描生成 OpenAPI 规范文档。</li><li>步骤： <ol><li>安装 <code>@nestjs/swagger</code> 与 <code>swagger-ui-express</code>。</li><li>在 <code>main.ts</code> 使用 <code>DocumentBuilder</code> 构建基础文档配置（标题、描述、版本等）。</li><li>通过 <code>SwaggerModule.createDocument</code> 生成文档对象。</li><li>使用 <code>SwaggerModule.setup(&#39;/api&#39;, app, document)</code> 挂载特定路由访问 Swagger UI。</li><li>可以在 Controller 中配合 <code>@ApiTags()</code>, <code>@ApiOperation()</code>, <code>@ApiResponse()</code>、在 DTO 中配合 <code>@ApiProperty()</code> 完善字段注释。</li></ol></li></ul></details><h2 id="如何在-nestjs-中实现缓存-cache-功能" tabindex="-1">如何在 NestJS 中实现缓存（cache）功能？ <a class="header-anchor" href="#如何在-nestjs-中实现缓存-cache-功能" aria-label="Permalink to &quot;如何在 NestJS 中实现缓存（cache）功能？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 提供了 <code>@nestjs/cache-manager</code> 用于统一管理缓存。</li><li>步骤： <ol><li>安装 <code>@nestjs/cache-manager</code> 与 <code>cache-manager</code>。</li><li>在 AppModule 中导入 <code>CacheModule.register()</code>。</li><li>在 Controller 中可以通过挂载全局/局部的拦截器 <code>@UseInterceptors(CacheInterceptor)</code> 自动缓存所有的 GET 请求。</li><li>也可以在 Service 中通过 <code>@Inject(CACHE_MANAGER)</code> 直接注入 Cache 实例，使用 <code>await this.cacheManager.get/set()</code> 手动操作缓存，支持接入 Redis 等后端存储。</li></ol></li></ul></details><h2 id="如何在-nestjs-中进行日志记录-logging" tabindex="-1">如何在 NestJS 中进行日志记录（logging）？ <a class="header-anchor" href="#如何在-nestjs-中进行日志记录-logging" aria-label="Permalink to &quot;如何在 NestJS 中进行日志记录（logging）？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 提供了内置的基于 <code>Logger</code> 类的日志记录系统。</li><li>基础用法：<code>private readonly logger = new Logger(MyService.name);</code>，通过 <code>this.logger.log()</code>, <code>error()</code>, <code>warn()</code>, <code>debug()</code> 输出信息。</li><li>全局日志：可以在微服务/程序初始化（<code>NestFactory.create</code>）时通过 <code>logger: [...]</code> 选项覆盖默认控制台输出。</li><li>自定义：可以实现 <code>LoggerService</code> 接口，集成如 Winston、Pino 等专业日志库模块，以支持不同环境持久化、日志分割等复杂需求。</li></ul></details><h2 id="什么是-nestjs-中的全局拦截器-global-interceptor-如何在-nestjs-中使用全局拦截器" tabindex="-1">什么是 NestJS 中的全局拦截器（global interceptor）？如何在 NestJS 中使用全局拦截器？ <a class="header-anchor" href="#什么是-nestjs-中的全局拦截器-global-interceptor-如何在-nestjs-中使用全局拦截器" aria-label="Permalink to &quot;什么是 NestJS 中的全局拦截器（global interceptor）？如何在 NestJS 中使用全局拦截器？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>全局拦截器是作用于整个应用程序中注册的所有控制器与路由的拦截器，通常用于统一返回体结构、记录全局访问日志、统一格式化响应数据等。</li><li>使用方式： <ol><li>方式一：在 <code>main.ts</code> 中直接使用 <code>app.useGlobalInterceptors(new TransformInterceptor())</code>。此法无法进行依赖解析注入。</li><li>方式二（推荐）：在 AppModule 的 <code>providers</code> 数组中使用令牌注册，以允许依赖注入： <code>{ provide: APP_INTERCEPTOR, useClass: TransformInterceptor }</code></li></ol></li></ul></details><h2 id="如何在-nestjs-中使用-passport-实现多种身份验证策略" tabindex="-1">如何在 NestJS 中使用 Passport 实现多种身份验证策略？ <a class="header-anchor" href="#如何在-nestjs-中使用-passport-实现多种身份验证策略" aria-label="Permalink to &quot;如何在 NestJS 中使用 Passport 实现多种身份验证策略？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li><code>@nestjs/passport</code> 包装了 Node 社区极其成熟的 Passport 库。</li><li>实现： <ol><li>每一个具体的验证实现可以看作一个 <strong>Strategy</strong> (策略)，继承 <code>PassportStrategy</code> 并实现 <code>validate</code> 校验逻辑（例如 local, jwt, github 等）。</li><li>Passport 根据策略将其结果塞入并生成 <code>req.user</code> 会话。</li><li>提供守卫支持：无需手写验证 Guard，直接继承 <code>AuthGuard(&#39;jwt&#39;)</code> 即可保护相应路由控制器。</li></ol></li></ul></details><h2 id="如何在-nestjs-中使用-jwt-进行身份验证" tabindex="-1">如何在 NestJS 中使用 JWT 进行身份验证？ <a class="header-anchor" href="#如何在-nestjs-中使用-jwt-进行身份验证" aria-label="Permalink to &quot;如何在 NestJS 中使用 JWT 进行身份验证？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>使用了 <code>@nestjs/jwt</code> 和 <code>@nestjs/passport</code> 加 <code>passport-jwt</code>。</li><li>流程： <ol><li><strong>登录生成 JWT</strong>：客户端凭密码成功登录后，使用注入的 <code>JwtService.sign(payload)</code> 基于私钥生成 JWT 字符串，并返回到前端。</li><li><strong>验证 JWT 策略</strong>：实现继承了 <code>PassportStrategy(Strategy, &#39;jwt&#39;)</code> 的 <code>JwtStrategy</code> 类。配置中解析从请求头部的 Authorization Bearer Token 中提取出的 payload，执行 <code>validate(payload)</code> 判断有效性。</li><li><strong>保护路由</strong>：通过给接口加上特定的 <code>@UseGuards(AuthGuard(&#39;jwt&#39;))</code>，对没有带有效 Token 的请求返回 401 失败。</li></ol></li></ul></details><h2 id="如何在-nestjs-中使用-acl-进行授权管理" tabindex="-1">如何在 NestJS 中使用 ACL 进行授权管理？ <a class="header-anchor" href="#如何在-nestjs-中使用-acl-进行授权管理" aria-label="Permalink to &quot;如何在 NestJS 中使用 ACL 进行授权管理？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>基于角色的访问控制（RBAC）/ 权限控制（ACL）在 NestJS 中结合**守卫（Guard）**进行处理。</li><li>流程： <ol><li>使用 <code>@SetMetadata(&#39;roles&#39;, [&#39;admin&#39;])</code> (推荐封装为自定义装饰器如 <code>@Roles(...)</code> )绑定当前路由需要的权限元信息。</li><li>编写 <code>RolesGuard</code>（实现 <code>CanActivate</code> 接口），通过 <code>Reflector</code> 反射读取路由绑定的元信息（roles），与验证后附加在 <code>req.user</code> 上的实际角色对比比对。</li><li>比对通过返回 true 授权放行，失败则返回 false 抛出错误（通常是 403 Forbidden）。</li></ol></li></ul></details><h2 id="如何在-nestjs-中实现异步任务-asynchronous-task" tabindex="-1">如何在 NestJS 中实现异步任务（asynchronous task）？ <a class="header-anchor" href="#如何在-nestjs-中实现异步任务-asynchronous-task" aria-label="Permalink to &quot;如何在 NestJS 中实现异步任务（asynchronous task）？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 内置和集成常用于处理定时或耗时的异步微型任务的方案： <ul><li><strong>定时任务 (Cron / Task Scheduling)</strong>：通过 <code>@nestjs/schedule</code> 库提供 <code>@Cron()</code>, <code>@Interval()</code>, <code>@Timeout()</code> 装饰器，实现后台自动化任务调度。</li><li><strong>消息队列 (Bull/Redis)</strong>：对于复杂的、消耗资源且可能需要重试机制的后台任务（如邮件、转码等），使用 <code>@nestjs/bull</code>。将消费者和生产者通过 Redis 解耦并处理庞大的作业队列。</li></ul></li></ul></details><h2 id="如何在-nestjs-中使用-docker-进行容器化部署" tabindex="-1">如何在 NestJS 中使用 Docker 进行容器化部署？ <a class="header-anchor" href="#如何在-nestjs-中使用-docker-进行容器化部署" aria-label="Permalink to &quot;如何在 NestJS 中使用 Docker 进行容器化部署？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>为了部署 NestJS 应用程序，必须创建 <code>Dockerfile</code> 让其以独立、可重用的环境运行。</li><li>大致编写逻辑： <ol><li>基础镜像：基于 Node.js LTS 镜像，如 <code>node:18-alpine</code>。</li><li>安装依赖：拷贝 <code>package.json</code>，执行 <code>npm install</code>。</li><li>编译发布包：拷贝所有源码，执行 <code>npm run build</code>。</li><li>多阶段构建：(生产镜像阶段) 仅复制必须模块，并运行 <code>node dist/main.js</code>。</li><li>准备 <code>.dockerignore</code> 避免将本地的 <code>node_modules</code> 复制进去。</li></ol></li></ul></details><h2 id="如何在-nestjs-中使用-kubernetes-进行容器编排和部署" tabindex="-1">如何在 NestJS 中使用 Kubernetes 进行容器编排和部署？ <a class="header-anchor" href="#如何在-nestjs-中使用-kubernetes-进行容器编排和部署" aria-label="Permalink to &quot;如何在 NestJS 中使用 Kubernetes 进行容器编排和部署？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>在 Docker 容器化基础之上，通过声明式配置文件(YAML) 告诉 Kubernetes 如何部署运行。</li><li>需要编写基本的： <ol><li><code>Deployment</code>: 定义你的 Nest 应用副本数、镜像和更新策略。</li><li><code>Service</code>: 暴露 Pod 中 Nest 应用的端口以提供内部负载均衡服务。</li><li><code>ConfigMap / Secret</code>: 注入应用需要的安全认证信息与环境变量。</li><li><code>Ingress</code>: （如果暴露到公网）用于路由外部 HTTP 请求访问你的 Service。</li></ol><ul><li>通过 <code>kubectl apply -f xx.yaml</code> 启动集群内的各个资源即可完成部署管理。</li></ul></li></ul></details><h2 id="什么是-nestjs-中的异步模块-async-module-如何使用异步模块" tabindex="-1">什么是 NestJS 中的异步模块（async module）？如何使用异步模块？ <a class="header-anchor" href="#什么是-nestjs-中的异步模块-async-module-如何使用异步模块" aria-label="Permalink to &quot;什么是 NestJS 中的异步模块（async module）？如何使用异步模块？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>当模块的提供者 (如数据库连接、统一配置中心等) 初始化需要根据异步操作或者提取环境变量时，应该使用异步模块模式（<strong>Dynamic Modules</strong> 动态模块异步定义）。</li><li>常用方法名如 <code>.registerAsync()</code> 或 <code>.forRootAsync()</code>。</li><li>实现：依赖于 <code>useFactory</code> 属性传递一个能够返回配置的工厂函数（可以使其为 <code>async</code>），并且可以使用 <code>inject</code> 属性请求依赖于已经注入的别的 Providers (比如 ConfigService) 读取配置文件后实例化。</li></ul></details><h2 id="nestjs-中如何进行环境变量配置" tabindex="-1">NestJS 中如何进行环境变量配置？ <a class="header-anchor" href="#nestjs-中如何进行环境变量配置" aria-label="Permalink to &quot;NestJS 中如何进行环境变量配置？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>NestJS 推荐使用 <code>@nestjs/config</code> 包，底层包裹了 <code>dotenv</code> 用于解析 <code>.env</code>。</li><li>在 AppModule 中导入：<div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ConfigModule.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">forRoot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  isGlobal: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 作用于全局</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  envFilePath: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;.env&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 指定路径，或者按条件配置不同的环境文件</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div></li><li>读取方式：随后可以在任意 Service 中注入内部集成的 <code>ConfigService</code> ，调用 <code>this.configService.get&lt;string&gt;(&#39;DATABASE_USER&#39;)</code> 安全读取。</li></ul></details>`,46)]))}const m=s(a,[["render",o]]);export{p as __pageData,m as default};
